import React from "react";
import Title from "../components/Title";
import { assets } from "../assets/assets";

const Contact = () => {
  return (
    <div>
      <div className="text-center text-2xl pt-10 border-t">
        <Title text1={"CONTACT"} text2={"US"} />
      </div>

      <div className="my-10 flex flex-col justify-center md:flex-row gap-10 mb-28">
        <img className="w-full md:max-w-[480px]" src={assets.contact_img} alt="" />
        <div className="flex flex-col justify-center items-start gap-6">
          <p className="font-semibold text-xl text-gray-600">Our store</p>
          <p className="text-gray-500">35, Ashok Nagar <br />Chennai, Tamilnadu, India </p>
          <p className="text-gray-500">Ph: 8910346621 <br /> Email: admin@museStyle.com</p>
          <p className="font-semibold text-xl text-gray-600">Careers at Muse Style</p>
          <p className="text-gray-500">Learn more about our teams and job openings</p>
          <button className="border border-black px-8 py-4 text-sm hover:bg-black">Explore Jobs</button>
        </div>
      </div>
    </div>
  );
};

export default Contact;
